blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>8 głównych części mowy</strong> języka angielskiego: rzeczowniki, czasowniki, przymiotniki, przysłówki, zaimki, przyimki, spójniki i wykrzykniki.",
    "rules": [
        {
            "label": "Treść Słowa",
            "color": "emerald",
            "text": "<strong>Rzeczowniki, czasowniki, przymiotniki, przysłówki</strong> – noszą główne znaczenie:",
            "example": "Szczęśliwy kot szybko biegnie."
        },
        {
            "label": "Słowa funkcyjne",
            "color": "blue",
            "text": "<strong>Zaimki, przyimki, spójniki</strong> – połącz słowa:",
            "example": "Ona jest w domu, a ja tutaj."
        },
        {
            "label": "Wykrzykniki",
            "color": "amber",
            "text": "<strong>Wykrzykniki</strong> – wyrażaj emocje:",
            "example": "Wow! Oh! Ups!"
        }
    ]
}

{
    "title": "1. Przegląd 8 części mowy",
    "intro": "Angielski ma 8 głównych części mowy:",
    "items": [
        {
            "label": "Rzeczownik",
            "title": "Rzeczownik",
            "subtitle": "Nazwy przedmiotów, ludzi, miejsc, idei (kot, Jan, miasto, kochać)"
        },
        {
            "label": "Czasownik",
            "title": "Czasownik",
            "subtitle": "Czynności lub stany (biegać, jeść, być, mieć)"
        },
        {
            "label": "Przymiotnik",
            "title": "Przymiotnik",
            "subtitle": "Opisuje rzeczowniki (duży, czerwony, piękny, mądry)"
        },
        {
            "label": "Przysłówek",
            "title": "Przysłówek",
            "subtitle": "Opisuje czasowniki, przymiotniki (szybko, bardzo, często)"
        },
        {
            "label": "Zaimek",
            "title": "Zaimek",
            "subtitle": "Zastępuje rzeczowniki (ja, ty, on, ona, ono, oni)"
        },
        {
            "label": "Przyimek",
            "title": "Przyimek",
            "subtitle": "Pokazuje związek (w, na, w, pod, pomiędzy)"
        },
        {
            "label": "Koniunkcja",
            "title": "Koniunkcja",
            "subtitle": "Łączy słowa i zdania (i, ale, lub, ponieważ)"
        },
        {
            "label": "Wykrzyknik",
            "title": "Wykrzyknik",
            "subtitle": "Wyraża emocje (Och! Wow! Ups! Hej!)"
        }
    ]
}

{
    "title": "2. Rzeczowniki - Rzeczowniki",
    "sections": [
        {
            "label": "Co to jest rzeczownik? (kot to coś)",
            "color": "emerald",
            "description": "<strong>Noun</strong> — це слово, що називає людину, місце, річ або ідею.",
            "examples": [
                {
                    "en": "The cat is sleeping.",
                    "ua": "Кіт спить. (cat — річ)"
                },
                {
                    "en": "Mary mieszka w Londynie.",
                    "ua": "Mary mieszka w Londynie. (Maryja to osoba, Londyn to miejsce)"
                },
                {
                    "en": "Miłość jest ważna.",
                    "ua": "Miłość jest ważna. (miłość jest ideą)"
                }
            ]
        },
        {
            "label": "Rodzaje rzeczowników",
            "color": "sky",
            "description": "Rzeczowniki są <strong>pospolite</strong> (pospolite) i <strong>właściwe</strong> (właściwe).",
            "examples": [
                {
                    "en": "pospolite: pies, miasto, książka",
                    "ua": "pospolite: pies, miasto, książka"
                },
                {
                    "en": "właściwy: Tom, Paryż, poniedziałek",
                    "ua": "właściwy: Tom, Paryż, poniedziałek"
                }
            ],
            "note": "<strong>Nazwy własne</strong> są zawsze pisane wielką literą."
        }
    ]
}

{
    "title": "3. Czasowniki - Czasowniki",
    "sections": [
        {
            "label": "Co to jest czasownik? (bieg – akcja)",
            "color": "emerald",
            "description": "<strong>Verb</strong> — це слово, що виражає дію або стан.",
            "examples": [
                {
                    "en": "She runs every morning.",
                    "ua": "Вона бігає щоранку. (run — дія)"
                },
                {
                    "en": "On jest nauczycielem.",
                    "ua": "On jest nauczycielem. (jest — stan)"
                },
                {
                    "en": "Mają dwójkę dzieci.",
                    "ua": "Mają dwójkę dzieci. (mieć - posiadanie)"
                }
            ]
        },
        {
            "label": "Rodzaje czasowników",
            "color": "sky",
            "description": "Główne typy: <strong>czasowniki określające czynność</strong>, <strong>czasowniki łączące</strong>, <strong>czasowniki pomocnicze</strong>.",
            "examples": [
                {
                    "en": "czynność: biegaj, jedz, pisz, graj, graj",
                    "ua": "дії: бігти, їсти, писати, грати"
                },
                {
                    "en": "łączenie: być, wydawać się, stać się[[CODX_SEG_4]]]połączenia: być, wydawać się, stać się",
                    "ua": "звʼязки: бути, здаватися, ставати"
                },
                {
                    "en": "pomocniczy: robić, mieć, będzie, może",
                    "ua": "pomocniczy: robić, mieć, będzie, może"
                }
            ]
        }
    ]
}

{
    "title": "4. Przymiotniki - Przymiotniki",
    "sections": [
        {
            "label": "Co to jest przymiotnik",
            "color": "emerald",
            "description": "<strong>Przymiotnik</strong> to słowo opisujące lub modyfikujące rzeczownik.",
            "examples": [
                {
                    "en": "duży dom",
                    "ua": "duży dom"
                },
                {
                    "en": "piękny kwiat",
                    "ua": "piękny kwiat"
                },
                {
                    "en": "Kawa jest gorąca.",
                    "ua": "Kawa jest gorąca."
                }
            ]
        },
        {
            "label": "Pozycja przymiotnika",
            "color": "sky",
            "description": "Przymiotnik znajduje się <strong>przed rzeczownikiem</strong> lub <strong>po czasownik łączący</strong>.",
            "examples": [
                {
                    "en": "wysoki mężczyzna (przed rzeczownikiem)",
                    "ua": "wysoki mężczyzna"
                },
                {
                    "en": "Ten mężczyzna jest wysoki. (po czasowniku łączącym)",
                    "ua": "The man is wysoki."
                }
            ],
            "note": "W języku angielskim przymiotnik <strong>nie zmienia się</strong> według płci i liczby: a wysoki mężczyzna, wysoka kobieta, wysocy ludzie."
        }
    ]
}

{
    "title": "5. Przysłówki - przysłówki",
    "sections": [
        {
            "label": "Co to jest przysłówek",
            "color": "emerald",
            "description": "<strong>Przysłówek</strong> to słowo modyfikujące czasownik, przymiotnik lub inny przysłówek.",
            "examples": [
                {
                    "en": "Biegnie szybko.",
                    "ua": "Biega szybko. (czasownik modyfikujący)"
                },
                {
                    "en": "Jest bardzo wysoki.",
                    "ua": "Jest bardzo wysoki. (modyfikuje przymiotnik)"
                },
                {
                    "en": "Ona mówi zbyt cicho.",
                    "ua": "Ona mówi zbyt cicho. (modyfikuje przysłówek)"
                }
            ]
        },
        {
            "label": "Tworzenie przysłówków",
            "color": "sky",
            "description": "Wiele przysłówków tworzy się przez dodanie <strong>-ly</strong> do przymiotnika.",
            "examples": [
                {
                    "en": "szybkie → szybko",
                    "ua": "szybkie → szybko"
                },
                {
                    "en": "ostrożny → ostrożnie",
                    "ua": "ostrożny → ostrożnie"
                },
                {
                    "en": "szczęśliwy → szczęśliwie",
                    "ua": "szczęśliwy → szczęśliwie"
                }
            ],
            "note": "Wyjątek: <strong>dobrze → dobrze</strong> (niezbyt dobrze), <strong>szybko → szybko</strong> (ta sama forma)."
        }
    ]
}

{
    "title": "6. Zaimki - Zaimki",
    "sections": [
        {
            "label": "Co to jest zaimek",
            "color": "emerald",
            "description": "<strong>Zaimek</strong> to słowo, które zastępuje rzeczownik, aby uniknąć powtórzeń.",
            "examples": [
                {
                    "en": "Mary jest lekarzem. Pracuje w szpitalu.",
                    "ua": "Mary jest lekarzem. Pracuje w szpitalu."
                },
                {
                    "en": "Książka jest ciekawa. Chodzi o historię.",
                    "ua": "Książka jest ciekawa. Chodzi o historię."
                }
            ]
        },
        {
            "label": "Rodzaje zaimków",
            "color": "sky",
            "description": "Główne typy: <strong>osobowy</strong> (osobisty), <strong>dzierżawczy</strong> (dzierżawczy), <strong>oznaczający</strong> (indykatywny).",
            "examples": [
                {
                    "en": "osobisty: ja, ty, on, ona, to, my, oni",
                    "ua": "osobiste: ja, ty, on, ona, to, my, oni"
                },
                {
                    "en": "zaborczy: mój, twój, jego, ona, nasz, ich[[CODX_SEG_23]]]zaborczy: mój, twój, jego, jej, nasz, ich",
                    "ua": "присвійні: мій, твій, його, її, наш, їхній"
                },
                {
                    "en": "pokazujący: to, tamto, te, te",
                    "ua": "wskazujące: to, tamto, te, tamte"
                }
            ]
        }
    ]
}

{
    "title": "7. Przyimki - Przyimki",
    "sections": [
        {
            "label": "Co to jest przyimek",
            "color": "emerald",
            "description": "<strong>Przyimek</strong> to słowo pokazujące związek między słowami (miejsce, czas, kierunek).",
            "examples": [
                {
                    "en": "Książka jest na stole.",
                    "ua": " (miejsce)"
                },
                {
                    "en": "Budzę się o 7 rano",
                    "ua": "Budzę się o 7:00 (czasu)"
                },
                {
                    "en": "Poszła do parku.",
                    "ua": "Poszła do parku. (kierunek)"
                }
            ]
        },
        {
            "label": "Najczęstsze przyimki",
            "color": "sky",
            "description": "Podstawowe przyimki określające miejsce, czas i ruch.",
            "examples": [
                {
                    "en": "miejsce: w, na, w, pod, za, pomiędzy",
                    "ua": "miejsce: w, na, blisko, pod, za, pomiędzy"
                },
                {
                    "en": "czas: o, w, w, przed, po Spójniki - Spójniki",
                    "ua": "час: о (годині), у (день), в (місяць), до, після"
                },
                {
                    "en": "movement: to, from, into, out of",
                    "ua": "рух: до, від, у (всередину), з"
                }
            ]
        }
    ]
}

{
    "title": "8. Conjunctions — Сполучники",
    "sections": [
        {
            "label": "Co to jest koniunkcja",
            "color": "emerald",
            "description": "<strong>Koniunkcja</strong> to słowo, które łączy słowa, frazy lub zdania.",
            "examples": [
                {
                    "en": "Lubię herbatę i herbatę kawa.",
                    "ua": "Uwielbiam herbatę i kawę."
                },
                {
                    "en": "Jest mądra, ale leniwa.",
                    "ua": "Jest mądra, ale leniwa."
                },
                {
                    "en": "Zostałem w domu, bo padał deszcz.",
                    "ua": "Zostałem w domu, bo było pada deszcz."
                }
            ]
        },
        {
            "label": "Typy spójników",
            "color": "sky",
            "description": "<strong>Koordynujące</strong> (równe) i podrzędne spójniki.",
            "examples": [
                {
                    "en": "coordinating: and, but, or, so, yet",
                    "ua": "сурядні: і, але, або, тому, однак"
                },
                {
                    "en": "subordinating: because, if, when, although",
                    "ua": "підрядні: тому що, якщо, коли, хоча"
                }
            ],
            "note": "<strong>FANBOYS</strong> to akronim słów For, And, Nor, But, Or, Yet, So.[[CODX_SEG_1]]]9. Wykrzykniki - Wykrzykniki"
        }
    ]
}

{
    "title": "9. Interjections — Вигуки",
    "sections": [
        {
            "label": "Co to jest wykrzyknik",
            "color": "emerald",
            "description": "<strong>Wykrzyknik</strong> to słowo lub fraza wyrażająca emocję lub reakcję.",
            "examples": [
                {
                    "en": "Wow! To niesamowite!",
                    "ua": "Wow! To niesamowite!"
                },
                {
                    "en": "Ups! Popełniłem błąd.",
                    "ua": "Och! Popełniłem błąd."
                },
                {
                    "en": "Hurra! Wygraliśmy!",
                    "ua": "Jej! Wygraliśmy!"
                }
            ]
        },
        {
            "label": "Częste wykrzykniki",
            "color": "sky",
            "description": "Wykrzykniki często występują samodzielnie i są oddzielone wykrzyknikiem.",
            "examples": [
                {
                    "en": "Och! Ach! Wow! Hej! Auć!",
                    "ua": "Och! I! Och! wesoły! Och!"
                },
                {
                    "en": "Cóż, myślę, że tak.",
                    "ua": "Cóż, myślę, że tak. (zmiękczanie)"
                }
            ],
            "note": "Wykrzykniki dodają emocji do mowy, ale w formalnym piśmie się ich unika."
        }
    ]
}

{
    "title": "10. Tabela podsumowująca części mowy",
    "intro": "Wszystkie 8 części mowy i ich funkcje:",
    "rows": [
        {
            "en": "Rzeczownik",
            "ua": "Rzeczownik",
            "note": "zawołania: kot, miasto, miłość"
        },
        {
            "en": "Czasownik",
            "ua": "Czasownik",
            "note": "działanie/stan: biegać, jest, mieć"
        },
        {
            "en": "Przymiotnik",
            "ua": "Przymiotnik",
            "note": "opisuje rzeczownik: duży, czerwony"
        },
        {
            "en": "Przysłówek",
            "ua": "Przysłówek",
            "note": "modyfikuje czasownik: szybko, bardzo"
        },
        {
            "en": "Zaimek",
            "ua": "Zaimek",
            "note": "zastępuje rzeczownik: ja, ona, oni"
        },
        {
            "en": "Przyimek",
            "ua": "Przyimek",
            "note": "relacja: w, na, w "
        },
        {
            "en": "Koniunkcja",
            "ua": "Koniunkcja",
            "note": "łączy: i, ale, ponieważ"
        },
        {
            "en": "Wykrzyknik",
            "ua": "Wykrzyknik",
            "note": "emocje: Wow! Oh! Ups!"
        }
    ],
    "warning": "📌 Jedno słowo może oznaczać różne części mowy w zależności od kontekstu: <strong>bieganie</strong> (czasownik: biegam) vs <strong>bieganie</strong> (rzeczownik: poranny bieg)."
}

{
    "title": "11. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pomieszanie przymiotnika z przysłówkiem.",
            "wrong": "Ona dobrze mówi po angielsku.",
            "right": "​​​​ <span class="font-mono">Ona mówi po angielsku cóż.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie przymiotnika zamiast przysłówka.",
            "wrong": "On szybko biegnie.",
            "right": "​​​​​​​ zaimek."
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Неправильний вибір займенника.",
            "wrong": "Ja i ja Tomek poszedł do szkoły.",
            "right": " ✅ <span class="font-mono">Tom i ja poszliśmy do szkoły.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Pominięcie przedimka przed rzeczownikiem.",
            "wrong": "Mam kot.",
            "right": " ✅ <span class="font-mono">Mam kota.</span>"
        }
    ]
}

{
    "title": "13. Ćwicz",
    "select_title": "Ćwiczenie 1. Rozpoznaj część mowy",
    "select_intro": "Określ, jaką częścią mowy jest wybrane słowo.",
    "selects": [
        {
            "label": "KOT śpi. (rzeczownik / czasownik / przymiotnik)",
            "prompt": "Jaka część mowy?"
        },
        {
            "label": "ONA SZYBKO skończyła swoją pracę. (przymiotnik / przysłówek / rzeczownik)",
            "prompt": "Jaka część mowy?"
        },
        {
            "label": "Poszli DO parku. (spójnik/przyimek/przysłówek) słowa.",
            "prompt": "Яка частина мови?"
        }
    ],
    "options": [
        "a",
        "b",
        "c"
    ],
    "input_title": "Вправа 2. Заповни пропуски правильною формою",
    "input_intro": "Обери правильну форму слова.",
    "inputs": [
        {
            "before": "Ona śpiewa (pięknie / pięknie)",
            "after": "→"
        },
        {
            "before": "On jest (dobrym/dobrym) uczniem",
            "after": "→"
        },
        {
            "before": "Pracują (ciężko / prawie) codziennie. (rzeczownik), biegnie (czasownik), szybko (przysłówek).",
            "after": "→"
        }
    ],
    "rephrase_title": "Вправа 3. Визнач усі частини мови в реченні",
    "rephrase_intro": "Розбери речення на частини мови.",
    "rephrase": [
        {
            "example_label": "Приклад:",
            "example_original": "The happy dog runs quickly.",
            "example_target": "The (article), happy (adjective), dog (noun), runs (verb), quickly (adverb)."
        },
        {
            "original": "1. Ona i ja poszliśmy wczoraj do szkoły.",
            "placeholder": "Rozpoznaj części mowy"
        },
        {
            "original": "2. Wow! Duży kot śpi na miękkim łóżku.",
            "placeholder": "Rozpoznaj części mowy"
        }
    ]
}

{
    "title": "Inne strony z podstawami gramatyki",
    "items": [
        {
            "label": "Części mowy – części mowy (bieżące)",
            "current": true
        },
        {
            "label": "Podstawowy porządek słów – kolejność słów w afirmacji",
            "current": false
        },
        {
            "label": "Kolejność słów w pytaniach i przeczeniach – pytania i przeczenia",
            "current": false
        }
    ]
}
